1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const COMPONENT_BLOCK_SIZE = 3;
5	const CURSED_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_THRESHOLD = 5;
7	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
8	const FIRST_INSURANCE_RATE = 0.1;
9	const LOYALTY_DISCOUNT_RATE = 0.2;
10	const LOYALTY_YEARS_THRESHOLD = 2;
11	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
12	
13	const MAIN_ITEM_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	};
19	
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	
22	const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);
23	
24	const componentGroupPremium = (count: number): number =>
25	  count === COMPONENT_BLOCK_SIZE
26	    ? COMPONENT_BLOCK_PREMIUM
27	    : count * COMPONENT_PREMIUM;
28	
29	const calculateBasePremiumSum = (items: any[]): number => {
30	  const mainItems = items.filter((item) => !isComponent(item));
31	  const components = items.filter(isComponent);
32	
33	  const mainBaseTotal = mainItems.reduce(
34	    (sum, item) => sum + (MAIN_ITEM_PREMIUMS[item.type] ?? 0),
35	    0,
36	  );
37	
38	  const componentCounts: Record<string, number> = {};
39	  for (const item of components) {
40	    componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
41	  }
42	
43	  const componentTotal = Object.values(componentCounts).reduce(
44	    (sum, count) => sum + componentGroupPremium(count),
45	    0,
46	  );
47	
48	  return mainBaseTotal + componentTotal;
49	};
50	
51	const calculateItemLevelSurcharges = (items: any[]): number => {
52	  const mainItems = items.filter((item) => !isComponent(item));
53	  return mainItems.reduce((sum, item) => {
54	    const base = MAIN_ITEM_PREMIUMS[item.type] ?? 0;
55	    const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
56	    const enchantmentSurcharge = item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
57	    return sum + cursedSurcharge + enchantmentSurcharge;
58	  }, 0);
59	};
60	
61	export const processScenario = (scenario: any): any => {
62	  const results: any[] = [];
63	  let quoteCount = 0;
64	  for (const step of scenario.steps) {
65	    if (step.op === "quote") {
66	      for (const item of step.items) {
67	        if (!MAIN_ITEM_PREMIUMS[item.type] && !COMPONENT_TYPES.has(item.type)) {
68	          throw new Error(`Unknown item type: ${item.type}`);
69	        }
70	      }
71	      const basePremiumSum = calculateBasePremiumSum(step.items);
72	      const itemSurcharges = calculateItemLevelSurcharges(step.items);
73	      const firstInsurance = basePremiumSum * FIRST_INSURANCE_RATE;
74	      const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremiumSum * LOYALTY_DISCOUNT_RATE : 0;
75	      const followUpDiscount = quoteCount > 0 ? basePremiumSum * FOLLOW_UP_DISCOUNT_RATE : 0;
76	      const premium = Math.ceil(basePremiumSum + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
77	      results.push({ premium });
78	      quoteCount++;
79	    }
80	  }
81	  return { results };
82	};
